#include <iostream>
#include <string>
#include <vector>
#include <cmath>

class GeometricShape {
public:
    virtual double getArea() const = 0;
    std::string getName() const {
        return shapeName;
    }
    virtual ~GeometricShape() = default;
protected:
    std::string shapeName;
};

class Rectangle : public GeometricShape {
public:
    Rectangle(double width, double height) : width_(width), height_(height) {
        shapeName = "Rectangle";
    }
    double getArea() const override {
        return width_ * height_;
    }
private:
    double width_;
    double height_;
};

class Triangle : public GeometricShape {
public:
    Triangle(double base, double height) : base_(base), height_(height) {
        shapeName = "Triangle";
    }
    double getArea() const override {
        return 0.5 * base_ * height_;
    }
private:
    double base_;
    double height_;
};

int main() {
    std::vector<GeometricShape*> shapes;
    shapes.push_back(new Rectangle(5.0, 4.0));
    shapes.push_back(new Triangle(6.0, 3.0));
    shapes.push_back(new Rectangle(-5.0, 4.0));
    shapes.push_back(new Triangle(0.0, 10.0));
    shapes.push_back(new Rectangle(-2.0, -3.0));
    shapes.push_back(new Triangle(-4.0, -5.0));

    for (const auto& shape : shapes) {
        std::cout << shape->getName() << " Area: " << shape->getArea() << std::endl;
    }

    for (const auto& shape : shapes) {
        delete shape;
    }
    return 0;
}
